440:             const last = &s.spans[last_idx];
441:             if (toLower(last.base) == lo and last.modifier == 0 and spanIsVowel(last.*)) {
442:                 // Cancellation check: if modifier already equals lo, strip it
443:                 // (can't happen here since modifier == 0)
444:                 last.modifier = lo;
445:                 return 1;
446:             }
447:         }
448:     }
449: 
450:     // ── w modifier ──
451:     if (lo == 'w') {
452:         // Look for target vowel: last a/o/u in the word
453:         var target: ?u8 = null;
454:         var i: u8 = 0;
455:         while (i < s.len) : (i += 1) {
456:             const b = toLower(s.spans[i].base);
457:             if (b == 'a' or b == 'o' or b == 'u') {
458:                 target = i;
459:             }
460:         }
461:         if (target) |ti| {
462:             const sp = &s.spans[ti];
463:             if (sp.modifier == 'w') {
464:                 // Cancellation: same modifier pressed again → enter literal
465:                 enterLiteral(s);
466:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
467:                 return 1;
468:             }
469:             if (sp.modifier != 0) {
470:                 // Already has a different modifier, can't apply w
471:                 // Treat w as a regular character → literal
472:                 enterLiteral(s);
473:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
474:                 return 1;
475:             }
476:             sp.modifier = 'w';
477:             // Re-apply tone placement since modified vowel changed
478:             const ct = currentTone(s);
479:             if (ct != 0) applyTone(s, ct);
480:             return 1;
481:         }
